// @ts-nocheck

export function normalizeDigestSql(sql) {
  return String(sql ?? '')
    .trim()
    .replace(/\s+/g, ' ')
    .replace(/`\s+/g, '`')
    .replace(/\s+`/g, '`')
    .replace(/\( \*/g, '(*')
    .replace(/\(\s+/g, '(')
    .replace(/\s+\)/g, ')');
}

export function substituteExplainPlaceholders(sql, database) {
  const parts = String(sql).split('?');
  if (parts.length <= 1) return sql;
  let out = parts[0];
  for (let i = 1; i < parts.length; i++) {
    const before = out.toUpperCase().trimEnd();
    let lit = '0';
    if (/\bLIMIT\s*$/.test(before) || /\bLIMIT\s*,\s*$/.test(before)) lit = '100';
    else if (/\bTABLE_SCHEMA\s*=\s*$/.test(before) || /\bSCHEMA\s*=\s*$/.test(before)) {
      lit = database ? `'${String(database).replace(/'/g, "''")}'` : "'mysql'";
    } else if (/\bTABLE_NAME\s*=\s*$/.test(before) || /\bNAME\s*=\s*$/.test(before)) lit = "'%'";
    else if (/\bLIKE\s*$/.test(before)) lit = "'%'";
    else if (/\bIN\s*\(\s*$/.test(before)) {
      lit = database ? `'${String(database).replace(/'/g, "''")}'` : "'x'";
    } else if (database) {
      lit = `'${String(database).replace(/'/g, "''")}'`;
    }
    out += lit + parts[i];
  }
  return out;
}

/** Runnable SQL from Query Store digest + optional schema for ? substitution. */
export function buildRunnableQuerySql(normalizedText, schemaName) {
  const base = normalizeDigestSql(normalizedText);
  if (!base) return 'SELECT 1;';
  const withLiterals = substituteExplainPlaceholders(base, schemaName);
  return withLiterals.endsWith(';') ? withLiterals : `${withLiterals};`;
}

/** Decode MySQL slow_log sql_text when API returns 0xHEX literals. */
export function decodeMysqlLogSql(value) {
  const raw = value == null ? '' : String(value);
  const s = raw.trim();
  if (!/^0x[0-9a-f]+$/i.test(s)) return raw;
  const hex = s.slice(2);
  let out = '';
  for (let i = 0; i < hex.length; i += 2) {
    const code = parseInt(hex.slice(i, i + 2), 16);
    if (!Number.isFinite(code)) continue;
    out += String.fromCharCode(code);
  }
  return out || raw;
}

/** Pick SQL text from a slow/general log row. */
export function sqlFromLogRow(row) {
  const raw = row?.sql_text ?? row?.argument ?? row?.query ?? row?.Info ?? row?.info ?? '';
  return decodeMysqlLogSql(raw);
}

export function sqlFromProcessRow(row) {
  return sqlFromLogRow(row);
}

export function isQueryableProcessSql(sql) {
  const s = String(sql ?? '').trim();
  if (s.length < 6) return false;
  return /^(SELECT|WITH|INSERT|UPDATE|DELETE|REPLACE|SHOW|CALL|CREATE|ALTER|DROP)\b/i.test(s);
}

const SQL_STOP_WORDS = new Set([
  'select', 'from', 'where', 'and', 'or', 'join', 'left', 'right', 'inner', 'outer', 'on', 'as',
  'in', 'not', 'null', 'is', 'by', 'order', 'group', 'limit', 'having', 'distinct', 'union', 'all',
  'insert', 'update', 'delete', 'set', 'values', 'into', 'case', 'when', 'then', 'else', 'end', 'with',
  'between', 'like', 'exists', 'asc', 'desc', 'for', 'use', 'index', 'key', 'primary', 'foreign',
]);

/** Approximate MySQL performance_schema DIGEST_TEXT from full SQL (literals → ?). */
export function approxDigestSql(sql) {
  let t = decodeMysqlLogSql(String(sql ?? '').trim());
  if (!t) return '';
  t = t.replace(/\/\*[\s\S]*?\*\//g, ' ');
  t = t.replace(/--[^\n\r]*/g, ' ');
  t = t.replace(/0x[0-9a-f]+/gi, '?');
  t = t.replace(/'(?:[^'\\]|\\.)*'/g, '?');
  t = t.replace(/"(?:[^"\\]|\\.)*"/g, '?');
  t = t.replace(/(?<![a-zA-Z0-9_])-?\d+(?:\.\d+)?(?:e[+-]?\d+)?/gi, '?');
  return t;
}

/** Aggressive normalization for cross-matching log SQL ↔ performance_schema digest. */
export function normSqlForMatch(s) {
  let t = normalizeDigestSql(s);
  t = t.replace(/^explain\s+(analyze\s+)?(format\s*=\s*json\s+)?/i, '');
  t = t.replace(/`/g, '');
  t = t.replace(/\s*;\s*$/, '');
  t = t.replace(/\s*,\s*/g, ',');
  t = t.replace(/\s*\(\s*/g, '(');
  t = t.replace(/\s*\)\s*/g, ')');
  t = t.replace(/\s+/g, ' ').trim().toLowerCase();
  return t;
}

/** Digest-shaped norm for matching process/slow-log SQL to stored DIGEST_TEXT. */
export function digestNormForMatch(sql) {
  return normSqlForMatch(approxDigestSql(sql));
}

function significantTokens(norm) {
  return norm.split(/\W+/).filter((x) => x.length > 2 && !SQL_STOP_WORDS.has(x));
}

function matchScore(inputNorm, candidateNorm) {
  if (!inputNorm || !candidateNorm) return 0;
  if (inputNorm === candidateNorm) return 100;
  if (inputNorm.includes(candidateNorm) || candidateNorm.includes(inputNorm)) {
    const short = inputNorm.length < candidateNorm.length ? inputNorm : candidateNorm;
    return short.length >= 24 ? 92 : 0;
  }
  const a = significantTokens(inputNorm);
  const b = significantTokens(candidateNorm);
  if (!a.length || !b.length) return 0;
  const setB = new Set(b);
  let overlap = 0;
  for (const tok of a) if (setB.has(tok)) overlap += 1;
  if (overlap === 0) return 0;
  const coverage = overlap / a.length;
  const density = overlap / Math.max(a.length, b.length);
  return Math.round(Math.min(88, coverage * 70 + density * 30));
}

function bestStoredByNorm(storedQueries, inputNorm, minScore = 70) {
  let best = null;
  let bestScore = 0;
  for (const q of storedQueries ?? []) {
    const qt = digestNormForMatch(q.normalizedText);
    const score = matchScore(inputNorm, qt);
    if (score > bestScore) {
      bestScore = score;
      best = q;
    }
  }
  return bestScore >= minScore ? { query: best, score: bestScore } : null;
}

function storedByDigestText(storedQueries, digestText) {
  const target = digestNormForMatch(digestText);
  if (!target) return null;
  for (const q of storedQueries ?? []) {
    if (digestNormForMatch(q.normalizedText) === target) return q;
  }
  return bestStoredByNorm(storedQueries, target, 95)?.query ?? null;
}

/** Match live performance_schema row to a tracked query (fingerprint / digest text). */
export function matchLiveRowToStored(storedQueries, liveRow) {
  const schema = String(liveRow?.SCHEMA_NAME ?? liveRow?.schema_name ?? liveRow?.database ?? '').trim();
  const digest = String(liveRow?.DIGEST ?? liveRow?.digest ?? '').trim();
  const digestText = String(liveRow?.DIGEST_TEXT ?? liveRow?.query ?? '').trim();

  if (digest && schema) {
    const fp = `mysql:${schema}:${digest}`.toLowerCase();
    for (const q of storedQueries ?? []) {
      const qfp = String(q.fingerprint ?? '').toLowerCase();
      if (qfp === fp || qfp.endsWith(`:${digest.toLowerCase()}`)) return q;
    }
  }

  if (digestText) {
    const target = digestNormForMatch(digestText);
    for (const q of storedQueries ?? []) {
      if (digestNormForMatch(q.normalizedText) === target) return q;
    }
    return matchStoredQueryBySql(storedQueries, digestText);
  }

  return null;
}

/** Find tracked query matching raw SQL from slow/general log. */
export function matchStoredQueryBySql(storedQueries, sqlText) {
  const norm = digestNormForMatch(sqlText);
  if (!norm) return null;
  return bestStoredByNorm(storedQueries, norm, 70)?.query ?? null;
}

export function matchLiveToStored(storedQueries, liveQueries, sqlText) {
  const inputDigest = digestNormForMatch(sqlText);
  if (!inputDigest) return null;

  const direct = bestStoredByNorm(storedQueries, inputDigest, 70);
  if (direct) return direct.query;

  let bestLive = null;
  let bestLiveScore = 0;
  for (const lq of liveQueries ?? []) {
    const digest = digestNormForMatch(lq.DIGEST_TEXT ?? lq.query);
    if (!digest) continue;
    const score = matchScore(inputDigest, digest);
    if (score > bestLiveScore) {
      bestLiveScore = score;
      bestLive = lq;
    }
  }
  if (bestLive && bestLiveScore >= 85) {
    const stored = storedByDigestText(storedQueries, bestLive.DIGEST_TEXT ?? bestLive.query);
    if (stored) return stored;
  }

  return null;
}

/** Returns match + score for UI (filter / highlight). */
export function findBestStoredMatch(storedQueries, liveQueries, sqlText) {
  const inputDigest = digestNormForMatch(sqlText);
  if (!inputDigest) return { query: null, score: 0 };

  let best = { query: null, score: 0 };
  for (const q of storedQueries ?? []) {
    const score = matchScore(inputDigest, digestNormForMatch(q.normalizedText));
    if (score > best.score) best = { query: q, score };
  }

  for (const lq of liveQueries ?? []) {
    const digest = digestNormForMatch(lq.DIGEST_TEXT ?? lq.query);
    const score = matchScore(inputDigest, digest);
    if (score >= 85 && score > best.score) {
      const stored = storedByDigestText(storedQueries, lq.DIGEST_TEXT ?? lq.query);
      if (stored) best = { query: stored, score };
    }
  }

  return best;
}

/** Hint line + query for Terminal / execute. */
export function composeForcedSql(querySql, hintSql) {
  const sql = String(querySql ?? '').trim();
  const hint = String(hintSql ?? '').trim();
  if (!hint) return sql;
  if (sql.includes(hint)) return sql;
  return `${hint}\n${sql}`;
}
